'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Loader2, Mail, Lock, LogIn, ArrowLeft } from 'lucide-react';

import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

const loginSchema = z.object({
  email: z.string().email('Email inválido'),
  password: z.string().min(6, 'Senha deve ter no mínimo 6 caracteres'),
});

type LoginFormValues = z.infer<typeof loginSchema>;

export default function LoginPage() {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { signIn } = useAuth();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginFormValues>({
    resolver: zodResolver(loginSchema),
  });

  const onSubmit = async (data: LoginFormValues) => {
    try {
      setIsSubmitting(true);
      await signIn(data.email, data.password);
    } catch {
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8 relative selection:bg-blue-600 selection:text-white">
      <Link href="/" className="absolute top-8 left-8 text-slate-500 hover:text-slate-900 flex items-center gap-2 transition font-medium">
        <ArrowLeft className="w-4 h-4" />
        Voltar para o início
      </Link>

      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="flex justify-center mb-6">
          <div className="w-16 h-16 rounded-2xl bg-white flex items-center justify-center p-3 shadow-xl border border-slate-100">
            <img src="/logo.png" className="w-full h-full object-contain" alt="Docentia" />
          </div>
        </div>
        <h2 className="text-center text-3xl font-extrabold text-slate-900 tracking-tight">
          Acesse sua conta
        </h2>
        <p className="mt-2 text-center text-sm text-slate-600">
          Ou{' '}
          <Link href="/registro" className="font-semibold text-blue-600 hover:text-blue-500 transition">
            crie uma conta gratuitamente
          </Link>
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-xl sm:rounded-xl sm:px-10 border border-slate-100">
          <form className="space-y-6" onSubmit={handleSubmit(onSubmit)}>
            <div>
              <Label htmlFor="email" className="text-slate-700 font-medium">Endereço de email</Label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Mail className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="email"
                  type="email"
                  autoComplete="email"
                  placeholder="admin@admin.com"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.email ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('email')}
                />
              </div>
              {errors.email && (
                <p className="mt-2 text-sm text-red-600">{errors.email.message}</p>
              )}
            </div>

            <div>
              <div className="flex items-center justify-between">
                <Label htmlFor="password" className="text-slate-700 font-medium">Senha</Label>
                <div className="text-sm">
                  <a href="#" className="font-semibold text-blue-600 hover:text-blue-500">
                    Esqueceu a senha?
                  </a>
                </div>
              </div>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="password"
                  type="password"
                  autoComplete="current-password"
                  placeholder="1234567890"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.password ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('password')}
                />
              </div>
              {errors.password && (
                <p className="mt-2 text-sm text-red-600">{errors.password.message}</p>
              )}
            </div>

            <div>
              <Button
                type="submit"
                disabled={isSubmitting}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-lg shadow-md text-base font-semibold text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 h-12 transition-all gap-2"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="animate-spin w-5 h-5 mr-2" />
                    Entrando...
                  </>
                ) : (
                  <>
                    <LogIn className="w-5 h-5 mr-2" />
                    Entrar
                  </>
                )}
              </Button>
            </div>
          </form>

          <div className="mt-8">
            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-slate-200" />
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-2 bg-white text-slate-500">
                  Acesso Restrito
                </span>
              </div>
            </div>
            <div className="mt-6 text-center text-sm text-slate-500">
              <p>Use sua conta Firebase.</p>
              <p>Se ainda nao tiver conta, clique em <b>crie uma conta gratuitamente</b>.</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Loader2, Mail, Lock, User, ArrowLeft, ArrowRight } from 'lucide-react';

import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

const registerSchema = z.object({
  name: z.string().min(3, 'Nome deve ter no minimo 3 caracteres'),
  email: z.string().email('Email invalido'),
  password: z.string().min(6, 'Senha deve ter no minimo 6 caracteres'),
  confirmPassword: z.string()
}).refine((data) => data.password === data.confirmPassword, {
  message: 'As senhas nao coincidem',
  path: ['confirmPassword'],
});

type RegisterFormValues = z.infer<typeof registerSchema>;

export default function RegisterPage() {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { signUp } = useAuth();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterFormValues>({
    resolver: zodResolver(registerSchema),
  });

  const onSubmit = async (data: RegisterFormValues) => {
    try {
      setIsSubmitting(true);
      await signUp({
        name: data.name,
        email: data.email,
        pass: data.password,
      });
    } catch {
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8 relative selection:bg-blue-600 selection:text-white">
      <Link href="/" className="absolute top-8 left-8 text-slate-500 hover:text-slate-900 flex items-center gap-2 transition font-medium">
        <ArrowLeft className="w-4 h-4" />
        Voltar para o inicio
      </Link>

      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="flex justify-center mb-6">
          <div className="w-16 h-16 rounded-2xl bg-white flex items-center justify-center p-3 shadow-xl border border-slate-100">
            <img src="/logo.png" className="w-full h-full object-contain" alt="Docentia" />
          </div>
        </div>
        <h2 className="text-center text-3xl font-extrabold text-slate-900 tracking-tight">
          Crie sua conta
        </h2>
        <p className="mt-2 text-center text-sm text-slate-600">
          Ja possui conta?{' '}
          <Link href="/login" className="font-semibold text-blue-600 hover:text-blue-500 transition">
            Entre por aqui
          </Link>
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-xl sm:rounded-xl sm:px-10 border border-slate-100">
          <form className="space-y-5" onSubmit={handleSubmit(onSubmit)}>
            <div>
              <Label htmlFor="name" className="text-slate-700 font-medium">Nome completo</Label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <User className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="name"
                  type="text"
                  placeholder="Seu nome"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.name ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('name')}
                />
              </div>
              {errors.name && (
                <p className="mt-2 text-sm text-red-600">{errors.name.message}</p>
              )}
            </div>

            <div>
              <Label htmlFor="email" className="text-slate-700 font-medium">Endereco de email</Label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Mail className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="email"
                  type="email"
                  placeholder="voce@escola.br"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.email ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('email')}
                />
              </div>
              {errors.email && (
                <p className="mt-2 text-sm text-red-600">{errors.email.message}</p>
              )}
            </div>

            <div>
              <Label htmlFor="password" className="text-slate-700 font-medium">Senha</Label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="password"
                  type="password"
                  placeholder="********"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.password ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('password')}
                />
              </div>
              {errors.password && (
                <p className="mt-2 text-sm text-red-600">{errors.password.message}</p>
              )}
            </div>

            <div>
              <Label htmlFor="confirmPassword" className="text-slate-700 font-medium">Confirmar senha</Label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-slate-400" />
                </div>
                <Input
                  id="confirmPassword"
                  type="password"
                  placeholder="********"
                  className={`pl-10 h-12 bg-slate-50 border-slate-200 focus:bg-white transition ${errors.confirmPassword ? 'border-red-300 ring-red-300 focus:border-red-500 focus:ring-red-500' : ''}`}
                  {...register('confirmPassword')}
                />
              </div>
              {errors.confirmPassword && (
                <p className="mt-2 text-sm text-red-600">{errors.confirmPassword.message}</p>
              )}
            </div>

            <div>
              <Button
                type="submit"
                disabled={isSubmitting}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-lg shadow-md text-base font-semibold text-white bg-slate-900 hover:bg-slate-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-slate-900 h-12 transition-all gap-2"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="animate-spin w-5 h-5 mr-2" />
                    Registrando...
                  </>
                ) : (
                  <>
                    Criar conta
                    <ArrowRight className="w-5 h-5 ml-2" />
                  </>
                )}
              </Button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import {
  LayoutDashboard,
  Calendar,
  Users,
  FileText,
  BookOpen,
  ClipboardList,
  BarChart3,
  Settings,
  LogOut,
  BookMarked,
  FileSpreadsheet,
  ChevronRight,
  Menu,
  X,
  Loader2,
  GraduationCap,
  Bell,
  Sparkles,
  CalendarDays,
  AlertCircle,
  CheckSquare,
  FileSearch,
  Layout,
  HelpCircle,
  Zap,
  FileUp,
  MoreVertical,
  Search,
  ChevronDown
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { CommandPalette } from '@/components/dashboard/CommandPalette';

type NavItem = {
  href: string;
  label: string;
  icon: any;
  exact?: boolean;
  badge?: string;
  isNew?: boolean;
};

type NavGroup = {
  title: string;
  items: NavItem[];
};

const navGroups: NavGroup[] = [
  {
    title: 'Painel',
    items: [
      { href: '/dashboard', label: 'Início', icon: LayoutDashboard, exact: true },
      { href: '/dashboard/minha-semana', label: 'Minha Semana', icon: CalendarDays },
      { href: '/dashboard/notificacoes', label: 'Notificações', icon: Bell },
    ]
  },
  {
    title: 'Gestão Pedagógica',
    items: [
      { href: '/dashboard/calendario', label: 'Calendário Escolar', icon: Calendar },
      { href: '/dashboard/turmas', label: 'Turmas', icon: Users },
      { href: '/dashboard/alunos', label: 'Alunos', icon: GraduationCap },
      { href: '/dashboard/planejamento', label: 'Planejamento', icon: Sparkles },
      { href: '/dashboard/diario', label: 'Diário de Classe', icon: ClipboardList },
      { href: '/dashboard/bncc', label: 'BNCC Explorer', icon: FileSearch },
      { href: '/dashboard/livro-didatico', label: 'Livro Didático', icon: BookOpen },
      { href: '/dashboard/projetos', label: 'Projetos Pedagógicos', icon: FileSpreadsheet },
    ]
  },
  {
    title: 'Avaliação e Documentos',
    items: [
      { href: '/dashboard/avaliacoes', label: 'Avaliações', icon: CheckSquare },
      { href: '/dashboard/relatorios', label: 'Relatórios', icon: BarChart3 },
      { href: '/dashboard/templates', label: 'Templates', icon: Layout },
      { href: '/dashboard/exportacoes', label: 'Exportações', icon: FileUp },
    ]
  },
  {
    title: 'Inteligência e Apoio',
    items: [
      { href: '/dashboard/consistencia', label: 'Consistência Pedagógica', icon: Zap },
      { href: '/dashboard/ajuda', label: 'Ajuda', icon: HelpCircle },
    ]
  }
];

function isActive(pathname: string, href: string, exact?: boolean) {
  if (exact) return pathname === href;
  return pathname === href || pathname.startsWith(href + '/');
}

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const { user, loading, signOut } = useAuth();
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({
    'Painel': true,
    'Gestão Pedagógica': true
  });

  useEffect(() => {
    if (!loading && !user) {
      router.push('/login');
    }
  }, [user, loading, router]);

  useEffect(() => {
    setIsMobileOpen(false);
    window.scrollTo(0, 0);
  }, [pathname]);

  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-16 h-16 rounded-[2rem] bg-white flex items-center justify-center p-3 shadow-2xl border border-slate-100 animate-pulse">
            <img src="/logo.png" className="w-full h-full object-contain" alt="Docentia" />
          </div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] animate-fade-in">Docentia Office</p>
        </div>
      </div>
    );
  }

  if (!user) return null;

  const toggleGroup = (title: string) => {
    setExpandedGroups(prev => ({ ...prev, [title]: !prev[title] }));
  };

  const allItems = navGroups.flatMap(g => g.items);
  const currentPage = allItems.find(item => isActive(pathname, item.href, item.exact));

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col lg:flex-row">
      {/* ─── Mobile Overlay ─── */}
      <div
        className={cn(
          "fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[60] transition-opacity duration-300 lg:hidden",
          isMobileOpen ? "opacity-100" : "opacity-0 pointer-events-none"
        )}
        onClick={() => setIsMobileOpen(false)}
      />

      {/* ─── Sidebar / Drawer Mobile ─── */}
      <aside
        className={cn(
          'fixed inset-y-0 left-0 w-[85vw] sm:w-80 h-full flex flex-col z-[70] transition-all duration-500 ease-[cubic-bezier(0.32,0.72,0,1)] lg:translate-x-0',
          'bg-white border-r border-slate-200/60',
          isMobileOpen ? 'translate-x-0 shadow-[20px_0_50px_-10px_rgba(0,0,0,0.1)]' : '-translate-x-full'
        )}
      >
        {/* Mobile Header Sidebar */}
        <div className="h-20 px-8 flex items-center justify-between border-b border-slate-100 shrink-0">
          <Link href="/dashboard" className="flex items-center gap-4 group">
            <div className="w-11 h-11 rounded-2xl bg-slate-950 flex items-center justify-center p-2.5 shadow-xl transition-all group-hover:scale-105 group-hover:rotate-2">
              <img src="/logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Docentia" />
            </div>
            <div className="flex flex-col">
              <span className="font-serif font-black text-2xl tracking-tight text-slate-800 italic leading-none">Docentia</span>
              <span className="text-[8px] font-black uppercase tracking-[0.25em] text-primary mt-1">Maestro</span>
            </div>
          </Link>
          <Button variant="ghost" size="icon" className="lg:hidden rounded-xl h-10 w-10 border border-slate-100" onClick={() => setIsMobileOpen(false)}>
            <X className="w-5 h-5 text-slate-400" />
          </Button>
        </div>

        {/* Scrollable Nav */}
        <nav className="flex-1 px-4 py-8 overflow-y-auto space-y-8 scrollbar-hide">
          {navGroups.map((group) => (
            <div key={group.title} className="space-y-2">
              <button
                onClick={() => toggleGroup(group.title)}
                className="w-full flex items-center justify-between px-4 mb-2 group"
              >
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                  {group.title}
                </p>
                <ChevronDown className={cn("w-3 h-3 text-slate-300 transition-transform", !expandedGroups[group.title] && "-rotate-90")} />
              </button>

              <div className={cn(
                "space-y-1 transition-all duration-300 overflow-hidden",
                expandedGroups[group.title] ? "max-h-[1000px] opacity-100" : "max-h-0 opacity-0"
              )}>
                {group.items.map((item) => {
                  const Icon = item.icon;
                  const active = isActive(pathname, item.href, item.exact);
                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      className={cn(
                        'flex items-center gap-4 px-4 py-3.5 rounded-2xl text-sm font-bold transition-all group relative border border-transparent',
                        active
                          ? 'bg-slate-900 text-white shadow-xl shadow-slate-200 border-slate-800'
                          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900 hover:border-slate-100'
                      )}
                    >
                      <div className={cn(
                        "w-8 h-8 rounded-xl flex items-center justify-center transition-colors",
                        active ? "bg-white/10" : "bg-slate-100 group-hover:bg-white"
                      )}>
                        <Icon className={cn('w-4 h-4 shrink-0', active ? 'text-white' : 'text-slate-400 group-hover:text-slate-900')} />
                      </div>
                      <span className="flex-1">{item.label}</span>
                      {item.badge && (
                        <span className="px-2 py-0.5 rounded-lg bg-rose-500 text-white text-[9px] font-black tracking-tighter">
                          {item.badge}
                        </span>
                      )}
                    </Link>
                  );
                })}
              </div>
            </div>
          ))}
        </nav>

        {/* User Profile Sidebar */}
        <div className="p-6 border-t border-slate-100 bg-slate-50/50">
          <div className="p-4 rounded-[2rem] bg-white border border-slate-100 shadow-sm flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-500 font-bold">
              {user.name?.charAt(0).toUpperCase() ?? 'P'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-[11px] font-black text-slate-800 truncate leading-none uppercase tracking-tighter">{user.name ?? 'Professor'}</p>
              <p className="text-[9px] text-slate-400 font-bold uppercase mt-1">Nível Maestro</p>
            </div>
            <button
              onClick={() => signOut()}
              className="w-9 h-9 rounded-xl flex items-center justify-center text-slate-400 hover:text-rose-600 hover:bg-rose-50 transition-all"
            >
              <LogOut className="w-4 h-4" />
            </button>
          </div>
        </div>
      </aside>

      {/* ─── Main Content ─── */}
      <main className="flex-1 lg:ml-80 flex flex-col min-h-screen relative pb-20 lg:pb-0">
        {/* Topbar Mobile & Desktop */}
        <header className="h-20 lg:h-24 bg-white/80 backdrop-blur-xl border-b border-slate-200/60 px-6 sm:px-12 flex items-center justify-between sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              className="lg:hidden h-12 w-12 rounded-2xl border border-slate-100 shadow-sm text-slate-600"
              onClick={() => setIsMobileOpen(true)}
            >
              <Menu className="w-5 h-5" />
            </Button>

            <div className="flex flex-col">
              <h2 className="text-xl lg:text-3xl font-serif font-bold text-slate-900 tracking-tight leading-none">
                {currentPage?.label ?? 'Escritório'}
              </h2>
              <div className="hidden sm:flex items-center gap-2 mt-1.5 opacity-40">
                <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-400">Março 2026 · Rede Municipal</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-6">
            <div className="hidden md:block w-72">
              <CommandPalette />
            </div>

            <div className="flex items-center gap-2">
              <Button variant="ghost" size="icon" className="md:hidden h-12 w-12 rounded-2xl text-slate-400 hover:text-slate-900 hover:bg-slate-50">
                <Search className="w-5 h-5" />
              </Button>
